import json
from typing import Any, Union


def flatten_ec2_metadata(data: Union[dict, str], max_depth: int = 20) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (Union[dict, str]): Input metadata as a pre-parsed dict or a raw JSON string.
            If a string is provided, json.loads() is called explicitly before processing.
        max_depth (int): Maximum nesting depth allowed. Defaults to 20. depth=0 means
            processing the root dict's direct children (first level of keys), depth=1 means
            processing the second level of keys, and so on. A ValueError is raised when
            depth reaches max_depth, so exactly max_depth levels of nesting are permitted.

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation
            (e.g., 'network.interfaces.0.mac'). If the root value is not a dict,
            returns {"" : root_value}.

    Raises:
        ValueError: If input is None or not a dict or str type.
        ValueError: If a JSON string input cannot be parsed by json.loads().
        ValueError: If nesting depth reaches max_depth during recursion.

    Examples:
        >>> result = flatten_ec2_metadata({"instance": {"id": "i-123", "type": "t2.micro"}}, max_depth=20)
        >>> result == {"instance.id": "i-123", "instance.type": "t2.micro"}
        True

        >>> try:
        ...     flatten_ec2_metadata({"a": {"b": {"c": "d"}}}, max_depth=1)
        ... except ValueError as e:
        ...     print("ValueError raised")
        ValueError raised
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError("Input must be a dict or a JSON string, not None or other types.")

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON string: {e}")

    if not isinstance(data, dict):
        return {"": data}

    result = {}

    def _flatten(obj: Any, prefix: str, depth: int) -> None:
        if isinstance(obj, dict):
            if depth >= max_depth:
                raise ValueError(
                    f"Nesting depth reached max_depth={max_depth}. Cannot process deeper."
                )
            for key, value in obj.items():
                new_key = f"{prefix}.{key}" if prefix else key
                _flatten(value, new_key, depth + 1)
        elif isinstance(obj, list):
            if depth >= max_depth:
                raise ValueError(
                    f"Nesting depth reached max_depth={max_depth}. Cannot process deeper."
                )
            for i, item in enumerate(obj):
                new_key = f"{prefix}." + str(i) if prefix else str(i)
                if isinstance(item, dict):
                    _flatten(item, new_key, depth + 1)
                else:
                    if depth >= max_depth:
                        raise ValueError(
                            f"Nesting depth reached max_depth={max_depth}. Cannot process deeper."
                        )
                    result[new_key] = item
        else:
            result[prefix] = obj

    _flatten(data, "", 0)
    return result

